{
// inputs: [0]=InputA [1]=InputB, float input from parameters
var inputA = inputs[0];
var inputB = inputs[1];
var op = GetChoice(parameters, "operator", "greaterThan");
var threshold = GetFloat(parameters, "threshold", 0.5f);
var lowerBound = GetFloat(parameters, "lowerBound", 0.3f);
var upperBound = GetFloat(parameters, "upperBound", 0.7f);
// For Condition we evaluate using pixel luminance of InputA vs threshold
var size = context.TileSize;
var result = new PixelBuffer(size, size);
// Compute average luminance of inputA as 'value'
float value = 0.5f;
if (inputA != null)
{
    double sum = 0;
    for (var y = 0; y < size; y += 4)
    for (var x = 0; x < size; x += 4)
    {
        var (r, g, b, _) = inputA.GetPixel(x, y);
        sum += 0.2126 * r + 0.7152 * g + 0.0722 * b;
    }
    value = (float)(sum / ((size / 4) * (size / 4)));
}
bool condition = op switch
{
    "greaterThan" => value > threshold,
    "lessThan" => value < threshold,
    "equalTo" => MathF.Abs(value - threshold) < 0.05f,
    "inRange" => value >= lowerBound && value <= upperBound,
    _ => value > threshold
};
var chosen = condition ? inputA : inputB;
if (chosen == null) chosen = condition ? inputB : inputA;
if (chosen != null)
    result.ParallelForEachPixel((x, y) => { var (r,g,b,a) = chosen.GetPixel(x,y); result.SetPixel(x,y,r,g,b,a); });
return result;
}
